from dagster import asset, define_asset_job, ScheduleDefinition, with_resources
from dagster_pyspark import pyspark_resource
from pyspark.sql import DataFrame

@asset(required_resource_keys={"pyspark"})
def raw_events(context) -> DataFrame:
    return context.resources.pyspark.spark_session.read.parquet("s3://bucket/raw/events/")

@asset
def cleaned_events(raw_events: DataFrame) -> DataFrame:
    return raw_events.dropDuplicates(["event_id"]).filter("event_ts IS NOT NULL")

events_job = define_asset_job("events_pipeline", selection=["raw_events", "cleaned_events"])
hourly = ScheduleDefinition(job=events_job, cron_schedule="0 * * * *")

spark.streams.addListener(new StreamingQueryListener() {
  override def onQueryProgress(event: QueryProgressEvent): Unit = {
    val prog = event.progress
    val inputRows = prog.numInputRows
    val outputRows = prog.sink.numOutputRows
    if (inputRows > 0 && outputRows == 0) {
      alertingClient.fire(s"Silent failure in ${prog.name}: consumed $inputRows, wrote 0")
    }
    metricsRegistry.gauge("spark.stream.input_rows").set(inputRows)
    metricsRegistry.gauge("spark.stream.output_rows").set(outputRows)
  }
  override def onQueryStarted(event: QueryStartedEvent): Unit = ()
  override def onQueryTerminated(event: QueryTerminatedEvent): Unit =
    if (event.exception.isDefined) alertingClient.fire(s"Query terminated: ${event.exception.get}")
})

import org.apache.spark.sql.streaming.StreamingQueryListener
import org.apache.spark.sql.streaming.StreamingQueryListener._

val freshnessListener = new StreamingQueryListener {
  override def onQueryProgress(event: QueryProgressEvent): Unit = {
    val progress = event.progress
    val batchDurationMs = progress.durationMs.getOrDefault("triggerExecution", 0L)
    val inputRate = progress.inputRowsPerSecond

    if (batchDurationMs > 60_000L)
      alertSlaBreach(s"Batch exceeded 60s SLA: ${batchDurationMs}ms")

    progress.sources.foreach { source =>
      val lagMs = System.currentTimeMillis() - source.endOffset.toLong
      if (lagMs > 900_000L)
        alertFreshnessViolation(s"Source lag ${lagMs}ms exceeds 15min SLA")
    }
  }
  override def onQueryStarted(event: QueryStartedEvent): Unit = ()
  override def onQueryTerminated(event: QueryTerminatedEvent): Unit = ()
}

spark.streams.addListener(freshnessListener)
